 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes';
 4	import { useIDEntities } from '@kubevirt-utils/components/NodeSelectorModal/hooks/useIDEntities';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { ActionGroup, Button, ButtonVariant, Modal, ModalVariant } from '@patternfly/react-core';
 7	
 8	import { getIntersectedQualifiedNodes } from '../../utils/helpers';
 9	import { AffinityLabel, AffinityRowData } from '../../utils/types';
10	
11	import AffinityForm from './AffinityForm/AffinityForm';
12	import { useNodeFieldQualifier } from './hooks/useNodeFieldQualifier';
13	import { useNodeLabelQualifier } from './hooks/useNodeLabelQualifier';
14	
15	type AffinityEditModalProps = {
16	  focusedAffinity: AffinityRowData;
17	  isOpen: boolean;
18	  nodes: IoK8sApiCoreV1Node[];
19	  nodesLoaded: boolean;
20	  onCancel: () => void;
21	  onSubmit: (affinity: AffinityRowData) => void;
22	  setFocusedAffinity: Dispatch<SetStateAction<AffinityRowData>>;
23	  title: string;
24	};
25	
26	const AffinityEditModal: FC<AffinityEditModalProps> = ({
27	  focusedAffinity,
28	  isOpen,
29	  nodes,
30	  nodesLoaded,
31	  onCancel,
32	  onSubmit,
33	  setFocusedAffinity,
34	  title,
35	}) => {
36	  const { t } = useKubevirtTranslation();
37	
38	  const [isDisabled, setIsDisabled] = React.useState(false);
39	  const expressions = useIDEntities<AffinityLabel>(focusedAffinity?.expressions);
40	  const fields = useIDEntities<AffinityLabel>(focusedAffinity?.fields);
41	
42	  const qualifiedExpressionNodes = useNodeLabelQualifier(nodes, nodesLoaded, expressions?.entities);
43	  const qualifiedFieldNodes = useNodeFieldQualifier(nodes, nodesLoaded, fields?.entities);
44	  return (
45	    <Modal
46	      footer={
47	        <ActionGroup>
48	          <Button
49	            onClick={() =>
50	              onSubmit({
51	                ...focusedAffinity,
52	                expressions: expressions?.entities,
53	                fields: fields?.entities,
54	              })
55	            }
56	            isDisabled={isDisabled}
57	            variant={ButtonVariant.primary}
58	          >
59	            {t('Save affinity rule')}
60	          </Button>
61	          <Button onClick={onCancel} size="sm" variant="link">
62	            {t('Cancel')}
63	          </Button>
64	        </ActionGroup>
65	      }
66	      className="ocs-modal co-catalog-page__overlay"
67	      isOpen={isOpen}
68	      onClose={onCancel}
69	      position="top"
70	      title={title}
71	      variant={ModalVariant.medium}
72	    >
73	      <AffinityForm
74	        qualifiedNodes={getIntersectedQualifiedNodes({
75	          expressionNodes: qualifiedExpressionNodes,
76	          expressions: expressions?.entities,
77	          fieldNodes: qualifiedFieldNodes,
78	          fields: fields?.entities,
79	        })}
80	        expressions={expressions}
81	        fields={fields}
82	        focusedAffinity={focusedAffinity}
83	        isSubmitDisabled={isDisabled}
84	        nodesLoaded={nodesLoaded}
85	        setFocusedAffinity={setFocusedAffinity}
86	        setSubmitDisabled={setIsDisabled}
87	      />
88	    </Modal>
89	  );
90	};
91	
92	export default AffinityEditModal;

